// Safety Check: ตรวจสอบ Modules ---
const missingModules = [];
if (typeof fetch === 'undefined') missingModules.push("fetch (node-fetch)");
if (typeof URL === 'undefined') missingModules.push("URL (url)");
if (typeof pLimit === 'undefined') missingModules.push("pLimit (p-limit)");
if (typeof AbortController === 'undefined') missingModules.push("AbortController (abort-controller)");
if (typeof https === 'undefined') missingModules.push("https (https)");

if (missingModules.length > 0) {
    node.error("CRITICAL: Missing Modules in Setup tab: " + missingModules.join(", "));
    node.status({ fill: "red", shape: "ring", text: "Missing Modules! Check Debug" });
    return null;
}

const n = msg.test ? !0 : !1
let now = Date.now();

let inititate = false
const setTopic = (topic) => msg.topic = topic

const xsysinfo = global.get("xsysinfo") || {}
const xlogin = global.get("xlogin") || {}
const xgetsetup = global.get("xgetsetup") || {}
const xstream = global.get("xstream") || {}
const xrefresh = global.get("xrefresh") || {}
const xgetxj = global.get("xgetxj") || {}

// --- Safe Agent Access ---
const httpsAgent = global.xwebAgents?.https;

// Handle Control Messages
if (msg.action) {
    if (msg.action === "changeSetting") {
        let { requestFrequency, requestTimeout,
            processesLimited, endpointConfigs, setEnableAll,
            setGetsysinfoAll, setGetsetupAll } = msg.payload

        if (requestFrequency) context.set("requestFrequency", requestFrequency);
        if (requestTimeout) context.set("requestTimeout", requestTimeout);
        if (processesLimited) context.set("processesLimited", processesLimited);
        if (endpointConfigs) context.set("endpointConfigs", endpointConfigs);

        requestFrequency = context.get("requestFrequency");
        requestTimeout = context.get("requestTimeout");
        processesLimited = context.get("processesLimited");
        endpointConfigs = context.get("endpointConfigs");

        if (setEnableAll) Object.values(context.get("threads") || {}).forEach(t => t.enabled = true);
        if (setGetsysinfoAll) Object.values(context.get("threads") || {}).forEach(t => t.sysinfoIsRequired = true);
        if (setGetsetupAll) Object.values(context.get("threads") || {}).forEach(t => t.getsetupIsRequired = true);

        msg.payload = { requestFrequency, requestTimeout, processesLimited, endpointConfigs };
        setTopic("Change Setting");
    } else if (msg.action === "start") {
        inititate = true;
        msg.payload = { inititate };
        setTopic("Initiate");
        context.set("running", false);
    }
}

if (!inititate && !context.get("running")) {
    if (!msg.action) {
        inititate = true;
    } else {
        return msg;
    }
}

// --- Limit Concurrency ---
let limitConfig = context.get("processesLimited") || 20;
let processed_withLimited = pLimit(limitConfig);

let commonOptions = {
    headers: { "content-type": "application/x-www-form-urlencoded" }
};

const res2JSON = async (res) => {
    if (!res.ok) throw new Error(`HTTP Error ${res.status}`);
    const text = await res.text();
    try {
        return JSON.parse(text);
    } catch (e) {
        throw new Error("Invalid JSON response");
    }
}

const params2Body = (params) => new URL.URLSearchParams(params).toString();
const getAgent = (urlStr) => (urlStr && urlStr.startsWith("https")) ? httpsAgent : null;

// FIX Core: immutable update helper
const updateThread = (mac, patch) => {
    let threads = context.get("threads") || {};
    let current = threads[mac] || {};

    const updated = {
        ...current,
        ...patch
    }
    context.set(`threads.${mac}`, updated);
    return updated;
}
/* safe get thread (cut reference) */
const getThread = (mac) => {
    let thread = context.get(`threads.${mac}`);
    if (!thread) {
        thread = {
            enabled: true,
            getsetupIsRequired: true,
            sysinfoIsRequired: true,
            mac
        };
        context.set(`threads.${mac}`, thread);
    }
    // Fix: return copy protected of mutation
    return { ...thread };
}
const ensureStore = (store, mac) => {
    if (!store[mac]) store[mac] = {};
    return store[mac];
}
// shallow clone
const safeEndpoint = (e) => ({
    mac: e.mac,
    host: e.host,
    urls: { ...e.urls },
    auth: { ...e.auth }
});

const timelapse = () => (Date.now() - now) / 1000;

const statusWithTs = (result, mac, part, host) => {
    // context.completeds = (context.completeds || 0) + 1;
    if (result !== "ok") {
        context.err = (context.err || 0) + 1;
        node.send({ payload: { result, mac, part, host }, topic: "Return Status" });
    }
    // node.status({ fill: "yellow", shape: "dot", text: `Running ${context.completeds}/${context.total || 0} err:${context.err || 0}` });
    return { mac, part, result, host, secs: timelapse() };
}

const createTimeoutController = () => {
    let controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), context.get("requestTimeout"));
    return { signal: controller.signal, timeoutId };
}

const safeClone = (obj) => {
    try {
        return structuredClone(obj);
    } catch {
        return {};
    }
}

const shallowCopy = (obj) => ({ ...obj });

const sysInfoOnData = (currentContext, endpointConfig) => (data) => {
    let { mac } = currentContext;
    let store = ensureStore(xsysinfo, mac);
    const { timestamp: _ts, info, ...restData } = data || {};
    let cleanInfo = info ? (({ languages, ...r }) => r)(info) : undefined;

    store.sysinfo_data = {
        mac,
        ts: Date.now(),
        ...restData,
        ...(cleanInfo && { info: cleanInfo })
    };
    delete currentContext.sysinfo_err;
    delete store.sysinfo_err;
    data = null;

    n && node.send({ payload: store.sysinfo_data, topic: "sysinfo" });

    if (store.sysinfo_data.error === "PERMISSION_DENIED") return false;
    updateThread(mac, { sysinfoIsRequired: false });
    return true;
}

const getsetupOnData = (currentContext, endpointConfig) => async (data) => {
    let { mac } = currentContext;
    let { host } = endpointConfig;

    let store = ensureStore(xgetsetup, mac);
    const { alarmCategories: _ac, maps: _maps, dpu: _dpu, devices, ...restSetup } = data || {};

    let cleanDevices = undefined;
    if (devices) {
        cleanDevices = {};
        for (const [devKey, devVal] of Object.entries(devices)) {
            if (!devVal) continue;

            const { cmds: _cmds, lng, gen, vrs, ...restDev } = devVal;

            let cleanLng = undefined;
            if (lng) {
                const { cmds: _lngCmds, ...restLng } = lng;
                cleanLng = restLng;
            }

            let cleanGen = undefined;
            if (gen) {
                const { devcom: _dc, dixelldev: _dd, dstp: _ds, desc: _desc, ...restGen } = gen;
                cleanGen = restGen;
            }

            let cleanVrs = undefined;
            if (vrs) {
                cleanVrs = {};
                for (const [vrsKey, vrsVal] of Object.entries(vrs)) {
                    if (!vrsVal) continue;
                    const { cwi: _cwi, chartDef, ...restVrsVal } = vrsVal;

                    let cleanChartDef = undefined;
                    if (chartDef) {
                        const { color: _color, ...restChartDef } = chartDef;
                        cleanChartDef = restChartDef;
                    }

                    cleanVrs[vrsKey] = {
                        ...restVrsVal,
                        ...(cleanChartDef && { chartDef: cleanChartDef })
                    };
                }
            }

            cleanDevices[devKey] = {
                ...restDev,
                ...(cleanLng && { lng: cleanLng }),
                ...(cleanGen && { gen: cleanGen }),
                ...(cleanVrs && { vrs: cleanVrs })
            };
        }
    }

    store.setup_data = {
        mac,
        ts: Date.now(),
        ...shallowCopy(restSetup),
        ...(cleanDevices && { devices: safeClone(cleanDevices) })
    };

    delete currentContext.setup_err;
    delete store?.setup_err;

    let hasError = data.error;
    data = null;
    cleanDevices = null;

    n && node.send({ payload: "setup processed", topic: "getsetup" });

    if (hasError === "PERMISSION_DENIED") {
        return await login(endpointConfig, getsetup);
    }

    updateThread(mac, { getsetupIsRequired: false });
    return statusWithTs("ok", mac, "getsetup", host);
}

const streamOnData = (currentContext, endpointConfig) => async (data) => {
    let { mac } = currentContext;
    let { host } = endpointConfig;

    let store = ensureStore(xstream, mac);

    // Filter: stream.inputs, stream.outputs
    const { stream: streamData, ...restData } = data || {};
    let cleanStream = streamData ? (({ inputs, outputs, ...r }) => r)(streamData) : undefined;

    store.stream_data = {
        mac, ts: Date.now(), ...restData, ...(cleanStream && { stream: cleanStream })
    };

    delete currentContext.stream_err;
    delete store?.stream_err;
    data = null;

    n && node.send({ payload: "stream processed", topic: "stream" });
    let freshContext = context.get(`threads.${mac}`) || currentContext;

    if (store.stream_data) {
        let sData = xstream[mac].stream_data;
        if (freshContext.sysinfoIsRequired) await sysinfo(endpointConfig);

        if (sData.error === "PERMISSION_DENIED") {
            delete xlogin[mac]?.login_data?.user?.sses;
            return await login(endpointConfig);
        } else if (sData.status === "ok") {
            // --- [CUT] Alarms removed here ---
            if (freshContext.getsetupIsRequired) return await getsetup(endpointConfig);

            let result = await login(endpointConfig, null, "refresh");
            if (result.result === "ok") {
                result.part = "stream+refresh";
                return result;
            }
            return statusWithTs("ok", mac, "stream", host);
        }
    }
    return statusWithTs("error", mac, "stream.unknown", host);
}

const loginOnData = (currentContext, callback, endpointConfig, action, retryCount = 0) => async (data) => {
    let { mac } = currentContext;
    let { host } = endpointConfig;
    n && node.send({ payload: "login response", topic: "login" });

    let store = ensureStore(xlogin, mac);

    // Filter: layout, user(devices, desktops, permissions, chart)
    const { layout: _layout, user, ...restLogin } = data || {};
    let cleanUser = user ? (({ devices, desktops, permissions, chart, ...r }) => r)(user) : undefined;

    const cleanedData = { mac, ts: Date.now(), ...restLogin, ...(cleanUser && { user: cleanUser }) };

    if (action) store[`login_${action}_data`] = cleanedData;
    else store.login_data = cleanedData;

    delete currentContext.login_err;
    delete store.login_err;

    let status = data.status;
    data = null;

    if (status !== "ok") {
        store.login_err = { mac, ts: Date.now(), status };

        // --- XJ Logic ---
        let xj = await getXj(endpointConfig);
        n && node.send({ payload: xj, topic: "XJPasswd" });
        if (xj) {
            endpointConfig.auth.username = "Administrator";
            endpointConfig.auth.password = xj.trim();
            let res = await login(endpointConfig, callback, action, retryCount + 1);
            if (res.result === "error") {
                res.part = "login.xj.invalid";
            }
            n && node.send({ payload: { res } });
            return res;
        } else {
            return statusWithTs("error", mac, "login.xj", host);
        }
    } else {
        if (typeof callback === 'function') return await callback(endpointConfig, retryCount + 1);
        return statusWithTs("ok", mac, "login");
    }
}

// --- Fetch Functions ---

const sysinfo = (endpointConfig) => {
    let { mac, host, urls } = endpointConfig;
    let currentContext = getThread(mac);
    if (!currentContext.enabled) return Promise.resolve(statusWithTs("blocked", mac, "sysinfo disabled", host));

    let controller = createTimeoutController();
    return fetch(urls.sysinfo, { method: "GET", ...commonOptions, signal: controller.signal, agent: getAgent(urls.sysinfo) })
        .then(res2JSON).then(sysInfoOnData(currentContext, endpointConfig))
        .catch(err => {
            xsysinfo[mac].sysinfo_err = { mac, ts: Date.now(), error: err.message };
            return statusWithTs("error", mac, "sysinfo", host);
        }).finally(() => clearTimeout(controller.timeoutId));
}

const getsetup = (endpointConfig) => {
    let { mac, host, urls } = endpointConfig;
    let currentContext = getThread(mac);
    if (!currentContext.enabled) return Promise.resolve(statusWithTs("blocked", mac, "getsetup disabled", host));

    let { login_data = {} } = xlogin[mac], { user = {} } = login_data, { sses } = user;
    if (!sses) return login(endpointConfig, getsetup);

    let controller = createTimeoutController();
    return fetch(urls.getsetup, {
        method: "POST", body: params2Body({ SSES: sses, language: "en-GB" }),
        ...commonOptions, signal: controller.signal, agent: getAgent(urls.getsetup)
    })
        .then(res2JSON).then(getsetupOnData(currentContext, endpointConfig))
        .catch(err => {
            xgetsetup[mac].setup_err = { mac, ts: Date.now(), error: err.message };
            return statusWithTs("error", mac, "getsetup", host);
        }).finally(() => clearTimeout(controller.timeoutId));
}

const xjEndpoint = "http://lotus.snapx.cloud/api/v1/xjpasswd"
const getXj = (endpointConfig) => {
    let { mac } = endpointConfig;
    let currentContext = getThread(mac);
    let controller = createTimeoutController();
    return fetch(xjEndpoint + `?MAC=${mac.toUpperCase()}`, {
        method: "GET", ...commonOptions, signal: controller.signal,
        agent: getAgent(xjEndpoint)
    })
        .then(res => res.text())
        .then(data => {
            delete currentContext.xj_err;
            delete xgetxj[mac].xj_err;
            xgetxj[mac].xj_data = { mac, ts: Date.now(), ...shallowCopy(data) };
            return data;
        })
        .catch(err => {
            xgetxj[mac].xj_err = { mac, ts: Date.now(), ...err };
            n && node.send({ payload: err, topic: "xj" });
            return null;
        }).finally(() => clearTimeout(controller.timeoutId));
}

const stream = (endpointConfig) => {
    let { mac, host, urls } = endpointConfig;
    let currentContext = getThread(mac);
    if (!currentContext.enabled) return Promise.resolve(statusWithTs("blocked", mac, "stream disabled", host));

    let { login_data = {} } = xlogin[mac], { user = {} } = login_data, { sses } = user;
    if (!sses) return login(endpointConfig);

    let controller = createTimeoutController();
    return fetch(urls.stream, {
        method: "POST", body: params2Body({ SSES: sses, complete: 1 }),
        ...commonOptions, signal: controller.signal, agent: getAgent(urls.stream)
    })
        .then(res2JSON).then(streamOnData(currentContext, endpointConfig))
        .catch(err => {
            xstream[mac].stream_err = { mac, ts: Date.now(), error: err.message };
            if (err.message === "PERMISSION_DENIED" || err.message.includes("Invalid JSON")) return login(endpointConfig);
            return statusWithTs("timeout", mac, "stream timeout", host);
        }).finally(() => clearTimeout(controller.timeoutId));
}

const login = (endpointConfig, callback, action, retryCount = 0) => {
    let { mac, host, urls, auth } = endpointConfig;
    let currentContext = getThread(mac);

    if (retryCount > 2) {
        return Promise.resolve(statusWithTs("error", mac, "login_loop", host));
    }

    if (!currentContext.enabled) return Promise.resolve(statusWithTs("blocked", mac, "login disabled", host));

    let params = { action: action || "login", auth_mode: auth.auth_mode, username: auth.username, password: auth.password, initparam: -1 };
    if (action === "refresh") {
        let { login_data = {} } = xlogin[mac], { user = {} } = login_data, { sses } = user;
        params.SSES = sses;
    }

    let controller = createTimeoutController();
    return fetch(urls.login, {
        method: "POST", body: params2Body(params),
        ...commonOptions, signal: controller.signal, agent: getAgent(urls.login)
    })
        .then(res2JSON).then(loginOnData(currentContext, callback, endpointConfig, action, retryCount))
        .catch(err => {
            xlogin[mac].login_err = { mac, ts: Date.now(), error: err.message };
            if (!action) return statusWithTs("error", mac, "login", host);
            return statusWithTs("error", mac, "login", host);
        }).finally(() => clearTimeout(controller.timeoutId));
}

// --- Main Execution ---
let auth = { auth_mode: "standard", username: "request", password: "027220245s" };
let mac = "000AF61469BD";
let url = "http://9.1.0.7:50007/";
let urls = {
    sysinfo: url + "cgi-bin/sysinfo.lua",
    login: url + "cgi-bin/login.lua",
    stream: url + "cgi-bin/stream.lua",
    getsetup: url + "cgi-bin/getsetup.lua",
    // alarms: url + "cgi-bin/alarms.lua" <--- [REMOVED]
};
let endpointConfig = { mac, urls, auth };
let test = msg.test ? [endpointConfig] : null;

if (context.get("enabled") && !context.get("running")) {
    context.set("running", true);
    let endpointConfigs = test || context.get("endpointConfigs") || [];

    if (endpointConfigs.length === 0) {
        context.set("running", false);
        node.status({ fill: "blue", shape: "ring", text: "No configs" });
        return msg;
    }

    context.completeds = 0; context.err = 0; context.total = endpointConfigs.length;
    node.send(msg);

    {/* BUILD BACKLOG NEW (Safe structure */ }
    let backlogs = {};
    endpointConfigs.forEach(e => {
        backlogs[e.mac] = {
            mac: e.mac,
            host: e.host,
            status: "pending",
            lastUpdate: Date.now(),
        };
        if (!xsysinfo[e.mac]) xsysinfo[e.mac] = {};
        if (!xlogin[e.mac]) xlogin[e.mac] = {};
        if (!xgetsetup[e.mac]) xgetsetup[e.mac] = {};
        if (!xstream[e.mac]) xstream[e.mac] = {};
        if (!xgetxj[e.mac]) xgetxj[e.mac] = {};
    });
    flow.set("backlogs", { ...backlogs });

    const tasks = endpointConfigs.map((endpointConfig) => processed_withLimited(() => {
        const ep = safeEndpoint(endpointConfig);
        return stream(ep).then((result) => {
            context.completeds = (context.completeds || 0) + 1;
            node.status({ fill: "yellow", shape: "dot", text: `Running ${context.completeds}/${context.total} err:${context.err || 0}` });
            return result;
        })
    }))

    Promise.allSettled(tasks).then((results) => {
        let totalSecs = (Date.now() - now) / 1000;
        let fulfilleds = results.filter(r => r.status === "fulfilled");
        let successes = fulfilleds.filter(r => r.value && r.value.result === "ok");
        let fails = fulfilleds.filter(r => r.value && r.value.result === "error");

        const resMap = (r) => (r.value ? [r.value.host, r.value.mac, r.value.result, r.value.secs] : ["err", "err", "crash", 0]);

        let currentBacklogs = flow.get("backlogs") || {};
        // ==== safe backlog load & ป้องกัน reference ====//
        currentBacklogs = JSON.parse(JSON.stringify(currentBacklogs));
        endpointConfigs.forEach(e => delete currentBacklogs[e.mac]);

        context.set("running", false);
        node.send([, { payload: { totalSecs, successes: successes.map(resMap), fails: fails.map(resMap) } }]);
        node.status({ fill: "green", shape: "dot", text: `Completed ${context.completeds}/${context.total}` });
    }).catch(err => {
        context.set("running", false);
        node.error("Critical Error in Main Loop: " + err.message);
        node.status({ fill: "red", shape: "ring", text: "Crash Recovered" });
    });

} else {
    if (context.get("running")) {
        node.status({ fill: "yellow", shape: "ring", text: `Busy...` });
    } else {
        node.status({ fill: "red", shape: "dot", text: `Disabled` });
    }
    msg.payload = { ...msg.payload, blocked: true };
    return msg;
}

