// Code added here will be run once
// whenever the node is started.
global.get("xsysinfo") || global.set("xsysinfo", {})
global.get("xlogin") || global.set("xlogin", {})
global.get("xgetsetup") || global.set("xgetsetup", {})
global.get("xstream") || global.set("xstream", {})
global.get("xrefresh") || global.set("xrefresh", {})
global.get("xgetxj") || global.set("xgetxj", {})

context.get("threads") || context.set("threads", {});
context.get("enabled") || context.set("enabled", false);

context.get("requestFrequency") || context.set("requestFrequency", 180000); //3 minutes
context.get("processesLimited") || context.set("processesLimited", 20);
context.get("requestTimeout") || context.set("requestTimeout", 20000);
context.get("endpointConfigs") || context.set("endpointConfigs", []);
context.get("running") || context.set("running", false);
context.get("timing") || context.set("timing", {});
context.completeds !== undefined || (context.completeds = 0);
context.total !== undefined || (context.total = 0);

// --- Safe Agent Creation ---
if (!global.xwebAgents) {
    try {
        // const agentOptions = { keepAlive: true, keepAliveMsecs: 3000, maxSockets: 100, maxFreeSocket: 10, timeout: 60000 };
        const agentOptions = { keepAlive: false };

        global.xwebAgents = {
            https: new https.Agent({ ...agentOptions, rejectUnauthorized: false })
        };
    } catch (e) {
        node.error("Failed to create HTTPS Agent: " + e.message);
    }
}

//Test
context.set("enabled", true);
context.set("running", false);
node.status({ fill: "green", shape: "dot", text: `Ready` });
